var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"드디어 정신이 드냐? 미나토?","JPN":"やっと目が覚めたか？　湊？","ENG":"Finally awake, Minato?","TWN":"你終於醒啦？南裕夏？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"마사키…? 너 괜찮은 거야?","JPN":"雅紀……？　お前平気なの？","ENG":"Masaki...? You good?","TWN":"雅紀……？你沒事吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"네 꼴을 봐라. 걱정은 내가 해야지.","JPN":"お前の格好を見ろよ。オレの方が心配したぞ。","ENG":"Say for yourself. You look worse than me.","TWN":"你看看你，該擔心的人是我吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"나야 금방 회복했지만……","JPN":"オレはすぐ回復したけど……","ENG":"I mean, I recovered pretty quickly, but...","TWN":"我是恢復得很快……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"넌 카운터가 아니었으면 수술도 못 받았을 거래.","JPN":"お前はカウンターじゃなかったら手術もできなかったってよ。","ENG":"The docs told me that you would've never survived the surgery if you weren't a Counter.","TWN":"但醫生說要不是你是制裁者，恐怕連手術都沒辦法做。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…그 정도야?","JPN":"……そんなに？","ENG":"Was it that bad?","TWN":"……那麼嚴重喔？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그래도 의사가 이제 잘 먹고 잘 쉬기만 하면 된다니까.","JPN":"でも医者がよく食べてよく寝たら治るって言ってた。","ENG":"But now, they say you'll be fine if you eat up and rest.","TWN":"不過醫生說你現在只要好好吃飯、好好休息就好。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"일단 이거라도 먹을래?","JPN":"まずはこれでも食っとくか？","ENG":"So, you wanna eat this or what?","TWN":"你要吃這個嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"사과? 토끼 모양이네.","JPN":"リンゴ？　うさぎの形だね。","ENG":"An apple? And it's in the shape of a rabbit.","TWN":"蘋果？還是兔子形狀欸。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"큭큭, 예쁘지? 사나에 씨가 깎아주고 간 거야.","JPN":"くく、可愛いだろう？　早苗さんが切ってくれたんだ。","ENG":"Haha, pretty, no? Sanae cut them like that for me.","TWN":"呵呵，很漂亮吧？是早苗削的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그 사람. 나이프 다루는 솜씨가 장난 아니더라.","JPN":"あの人。ナイフを扱うの上手だったな。","ENG":"You should've seen how skillful she was with a knife.","TWN":"她的刀工真的超強的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"분명 집안일도 엄청 소질있고 가정적이겠지?","JPN":"きっと家事もできて、家庭的なんだろうな？","ENG":"I bet she's also really kind and good at housework too. Ha ha.","TWN":"她一定很會做家事，會是個賢妻良母吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"이거 엄청 맛있네요.","JPN":"これ本当に美味しいですね。","ENG":"It's delicious too.","TWN":"這個好好吃喔。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"얌마! 넌 그만 먹어! 사나에 씨가 나한테 준 거라고!","JPN":"おい！　お前は食うなよ！　早苗さんがオレにくれたんだ！","ENG":"Hey! Stop eating that! She left them for me!","TWN":"喂！你別再吃啦！那是早苗給我的！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"싫어요! 약속한 돈이나 내놔요! 이 사기꾼!","JPN":"嫌です！　約束したお金を出しなさい！　この詐欺師！","ENG":"No! Give me my money, you scammer!","TWN":"不要！你先把說好的錢付清吧！你這個騙子！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"……사나에 씨가 다녀갔어?","JPN":"……早苗さんが来てたの？","ENG":"...Sanae came by?","TWN":"……早苗來過嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"아, 당주님 동생도 너 수술 끝날 때까지 기다리고 있었어.","JPN":"あ、当主の妹もお前の手術が終わるまで待ってたぞ。","ENG":"Oh, even Lady Nanahara's sister waited until your surgery was done.","TWN":"對了，堂主的妹妹也一直等到你手術結束。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"네 옆에서 한동안 편지를 쓰는 것 같더니, 깨어나면 전해달라던데?","JPN":"お前の隣で手紙を書いていたけど、起きたら渡すようにって言ってたな？","ENG":"She was next to you the whole time writing a letter that she wanted me to give when you woke up.","TWN":"她在等你的時候似乎在寫信，請我等你醒來後交給你。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"편지……?","JPN":"手紙……？","ENG":"A letter...?","TWN":"信……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"narration","speaker":null,"text":{"KOREA":"가문연합의 일원으로서 함께 싸워 주셔서 감사합니다.","JPN":"連合の一員としてともに戦っていただき、ありがとうございました。","ENG":"Thank you for fighting with us as a member of the Family Alliance.","TWN":"謝謝你以家族聯盟一員的身分一起作戰。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"narration","speaker":null,"text":{"KOREA":"나유카 공은 당연한 의무라고 생각하시겠지만, 주는만큼 보답하는 것이 마땅한 처사라고 생각합니다.","JPN":"奈由香殿は当たり前の義務だと思っていらっしゃるでしょうが、私は受けた恩には報いるべきだと思っています。","ENG":"You may think of it as your natural duty, Mr. Nayuka, but I believe we must give back as much as we received.","TWN":"雖然你可能會覺得這是你當盡的義務，但我認為知恩圖報才是處世之道。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"narration","speaker":null,"text":{"KOREA":"그래서 당주님과 의논하여 답례를 준비했습니다.","JPN":"それで当主と話し合って、お礼を用意しました。","ENG":"So, after discussing with Lady Nanahara, we have prepared you a gift.","TWN":"所以我和堂主討論後，準備了一份謝禮要給你。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"narration","speaker":null,"text":{"KOREA":"괜찮으시다면 조부님과 함께 다시 뵙기를 바랍니다.","JPN":"差支えなければ、お祖父様ともまたお会いしたいです。","ENG":"If you do not mind, I suggest you visit us again with your grandparents.","TWN":"可以的話，希望日後有機會再次拜訪你爺爺。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"나유카 공의 쾌차와 복귀를 기원하며… 나나하라 치후유.","JPN":"奈由香殿の快癒と復帰を願って……七原千冬。","ENG":"We wish you a swift recovery and return, Mr. Nayuka... Yours sincerely, Nanahara Chifuyu.","TWN":"祝你早日康復……七原千冬。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"누가 사기꾼이라는 거야! 계약은 제대로 이행했잖아! 오오가미 흑막조 지분의 50%라고!","JPN":"誰が詐欺師だ！　契約はちゃんと果たしただろ！　大神黒幕組の持ち分の50%だぞ!","ENG":"Who're you calling a scammer?! I did everything according to the contract! 50% of Ogami's Shadow Group's shares!","TWN":"你說誰是騙子！我明明就有遵守約定！大神黑幕組50%的股份！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"거짓말! 무슨 엄청난 거대조직인 것처럼 자랑하더니 당신들 둘 뿐인 빈털터리 조직이었잖아요!","JPN":"嘘つき！　偉そうな組織みたいに自慢しておいて、結局あなたたち二人だけの貧乏組織だったじゃないですか！","ENG":"Liar! You were boasting about it as if it were some huge organization! But it turns out that it's just you two with nothing else at all!","TWN":"你騙人！你說的好像是多麼龐大的組織似的，結果是只有你們二個人的窮光蛋組織！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"어리석은 여인이로군! 고작 현재라는 틀에 얽매여 흑막조 미래의 가능성을 얕보는 거냐!","JPN":"愚かな女だな！　現在という概念に囚われ、黒幕組の未来の可能性を甘く見るとは！","ENG":"Foolish girl! Are you underestimating the potential we have for the future for something as futile as money?","TWN":"真是愚蠢的女人！這麼短視近利，你是在小看黑幕組未來的潛力嗎！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"웃기시네! 그딴 소꿉놀이 같은 조직의 지분 같은 거 필요 없거든요! 돈으로 줄 때까지 안 돌아갈 거예요!","JPN":"何が未来ですか！　そんなままごと組織の持ち分なんて要りません！　お金で払うまで帰りませんから！","ENG":"Don't kid yourself! I don't need shares of an organization that plays house! I'm not going anywhere until I get my money!","TWN":"說笑嗎你！我才不要這種小孩子扮家家酒的組織的股份！在你把錢付清前我是不會回去的！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"마사키. 이런 게 편지 안에 들어있던데. 뭔지 알아?","JPN":"雅紀。こんな物が手紙の中に入ってたけど。なんだかわかる？","ENG":"Masaki, do you know what this is? It was included in the letter.","TWN":"雅紀，這東西好像是裝在信裡的，你知道是什麼嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"앗? 설마 돈인가요?!","JPN":"あっ？　もしかしてお金ですか！？","ENG":"Huh? Is it money?!","TWN":"什麼？難道是錢？！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"이건…… 당주들에게만 주는 나나하라 가옥의 열쇠잖아?","JPN":"これは……当主だけに与えられる七原家屋の鍵じゃないか？","ENG":"This... is the key to the Nanahara house that is only given to the family leaders.","TWN":"這是……只有堂主才有的……七原宅邸鑰匙？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"아마도 널 나유카 가문의 정식 당주로 인정한다는 뜻이겠지.","JPN":"おそらくお前の事を奈由香家の正式な当主として認めるということだろう。","ENG":"I guess that means you are now officially recognized as the head of the Nayuka family.","TWN":"應該是承認你是你們家族正式的堂主吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"정식…… 당주.","JPN":"正式な……当主。","ENG":"An official... head of the family.","TWN":"正式的……堂主。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"잘 됐네. 거긴 전문 의료진들이 항시 대기 중이고, 보안설비도 잘 갖춰져있거든.","JPN":"よかったじゃないか。そこは専門医療陣が揃っていて、セキュリティーもばっちりだぞ。","ENG":"Good for you. They have professional medical personnel on hand, and security is extremely tight.","TWN":"正好，那裡有專業的醫療團隊待命，保安設備也很完善。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"네 할아버지를 함께 모셔가면 더 이상 혼자 남겨둘 걱정은 하지 않아도 될 거야.","JPN":"お前のとこのお祖父さんを連れていけば、もう一人になる心配はしなくてもいいだろう。","ENG":"If you take your grandfather with you, you won't have to worry about leaving him alone.","TWN":"帶你爺爺一起去的話，就不用再擔心留他自己一個人啦。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"뭐야. 그런 거면 집처럼 팔지도 못하는 거잖아요.","JPN":"なんだ。そんなんじゃ家みたいに売ることもできないんですね。","ENG":"Ugh... But then you can't sell it for money.","TWN":"什麼嘛，這樣的話，那這房子是不能賣的吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"돈은 나중에라도 줄 테니 좀 조용히 해.","JPN":"金は後で払うから、いい加減にしろ。","ENG":"I'll give you your money later, so just shut up, okay?","TWN":"錢我以後再給你，你閉嘴啦。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"너도 카운터로서 사람들을 지켜냈다는 자부심 정도는 있지 않냐?","JPN":"お前もカウンターとして人々を守ったというプライドぐらいはあるだろう？","ENG":"Don't you feel pride as a Counter for saving all those lives?","TWN":"你也是制裁者，難道就沒有保護人的使命感嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"아뇨, 역사에 길이남을 영웅이 된다 해도 쫄쫄 굶거나 단명하는 배드엔딩은 사양이거든요.","JPN":"いいえ、歴史に残る英雄になれるとしても、貧乏になるとか早死にするバッドエンドは遠慮します。","ENG":"No. I refuse to get a bad ending of starving to death even if I become one of the greatest heroes of all time.","TWN":"沒有，就算要成為名垂青史的英雄，我也拒絕餓肚子或短命的結局。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"나 참.","JPN":"まったく。","ENG":"Ugh...","TWN":"真是的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그래서, 미나토 넌 퇴원하면 어떻게 할 셈이야?","JPN":"それで、湊は退院したらどうするつもりだ？","ENG":"Anyway, what are you going to do after you get discharged from here, Minato?","TWN":"所以南裕夏，你出院後打算怎麼辦？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"가야지.","JPN":"行かなきゃね。","ENG":"I should go.","TWN":"當然要回去。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"내가 있어야 할 곳으로.","JPN":"僕のいるべき場所に。","ENG":"Where I belong.","TWN":"回到我該待的地方。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"돌아왔습니다, 당주님.","JPN":"ただいま戻りました、当主。","ENG":"I have returned, Lady Nanahara.","TWN":"堂主，我回來了。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"어서 와, 치후유.","JPN":"お帰り、千冬。","ENG":"Welcome home, Chifuyu.","TWN":"你回來啦。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"다들 잘 모셔드리고 왔니?","JPN":"みんな大丈夫だった？","ENG":"Did you escort everyone well?","TWN":"大家都還好嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"예. 미나토님도, 마사키님도 수술을 잘 마치셨다고 하니 곧 회복될 겁니다.","JPN":"はい。湊様も、雅紀様も手術は無事終わったと聞いたのでもうすぐ回復されるでしょう。","ENG":"Yes. Mr. Minato and Mr. Masaki had successful operations done, and will fully recover soon.","TWN":"是，南裕夏和雅紀的手術很成功，很快就會恢復健康的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"결계를 복원하는 의식은 잘 치르셨습니까?","JPN":"結界の復元儀式はどうでしたか？","ENG":"Did the barrier restoration ritual go well?","TWN":"復原結界的儀式還順利嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"의식은 끝났지만…… 결계옥의 힘이 예전보다 많이 약해졌어.","JPN":"儀式は終わったけど……結界玉の力が以前よりだいぶ弱くなってしまったわ。","ENG":"The ritual is done, but... Akaitama's power is weaker than it was before.","TWN":"儀式結束了……但結界玉石的力量變得比之前弱很多。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"길어도 일 년을 버티는 게 고작일 거야.","JPN":"長くても一年を持たせるのが限界でしょう。","ENG":"It might only last for a year at most.","TWN":"最長也只能撐一年的時間。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"결계옥의 힘이 한계에 다다르면……","JPN":"結界玉の力に限界がきたら……","ENG":"If Akaitama is depleted of all its power...","TWN":"等結界玉石的力量到達極限後……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그때는 제가 책임을 질 테니 걱정마십시오.","JPN":"その時は私が責任を取るので、ご心配なく。","ENG":"I will take on the responsibility, so do not worry.","TWN":"別擔心，到時候就交給我負責。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"명부신의 영혼 중 절반은 저에게 깃들었으니까요.","JPN":"冥府の神の魂の半分は私に宿りましたから。","ENG":"Half of the Nether God's soul is resting within me.","TWN":"畢竟冥府神的靈魂有一半滲入到我的體內。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"치후유…… 그건……","JPN":"千冬……それは……","ENG":"Chifuyu... But that's...","TWN":"千冬……那個……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그런 표정 짓지 마십시오.","JPN":"そんな顔しないでください。","ENG":"Please. There is no need to make that face.","TWN":"請別露出那種的表情。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"호위는 당주를 지키고, 당주는 가문을 이어나간다.","JPN":"護衛は当主を守り、当主は家を引き継ぐ。","ENG":"A bodyguard protects Lady Nanahara, and she leads the family.","TWN":"護衛的責任是保護堂主，堂主的責任是傳承家族。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"이것은 제가 바라오던 가장 이상적인 이야기입니다.","JPN":"これは私が願ってやまなかった理想的な話です。","ENG":"This is what I have been hoping for.","TWN":"這就是我認為最理想的狀態。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그렇게 속단하지 않아도 돼. 분명 다른 방법을 찾을 수 있을 거야.","JPN":"そんなに決めつける必要はないわ。きっと他の方法が見つかるはずよ。","ENG":"You should not jump to conclusions so easily. I am sure there will be another way.","TWN":"你也不用這樣急著下定論，一定能找到其他辦法的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"저도…… 그럴 수만 있다면 좋겠습니다만.","JPN":"私も……それができればいいのですが。","ENG":"I too... would like that if it were possible.","TWN":"我……也希望如此。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"그렇게 될 거다.","JPN":"できるはずじゃ。","ENG":"I am most certain it will.","TWN":"一定會的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"나오님……?","JPN":"ナオ様……？","ENG":"Miss Nao...?","TWN":"奈緒大人……？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"너희를 이렇게 일찍 다시 만나게 될 줄은 몰랐다만……","JPN":"お主たちにこんなに早く再会することになるとは思わなかったが……","ENG":"I didn't expect the two of you to meet again so soon...","TWN":"沒想到會這麼快就再見到你們……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"어쨌든 일 년 안에 우리는 해결책을 찾을 거다.","JPN":"とにかく一年以内にわしらは解決策を見つける。","ENG":"Anyway, we will have to find a solution within a year.","TWN":"不管怎麼樣，我們會在一年內找到解決辦法的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"이건 단순한 약속이 아니라, 관리국과의 거래야.","JPN":"これは単なる約束ではない、管理局との取引じゃ。","ENG":"This isn't just a promise. This is a deal with the Administration.","TWN":"這不是單純的約定，而是和管理局的交易。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"관리국…… 말입니까?","JPN":"管理局……ですか？","ENG":"The... Administration?","TWN":"管理局……嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"방법이 있다면……! 그게 무엇이든 따르겠습니다.","JPN":"方法があるなら……！　それが何だって従います。","ENG":"If there is any way...! I will gladly follow.","TWN":"只要有辦法……！無論要我們做什麼我們都願意。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"좋아. 당주 나나하라 치나츠 이하 가문연합원들은 듣도록.","JPN":"よし。当主七原千夏と連合員はよく聞け。","ENG":"Very well. Then, Nanahara Chinatsu, head of the Nanahara family, and all those you lead, listen closely.","TWN":"很好。堂主七原千夏帶領的家族聯盟成員聽著，"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"너희는 오늘부로 당분간……","JPN":"お主たちは今日をもってしばらく……","ENG":"For the time being, starting today...","TWN":"從今天起，你們將暫時……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"이 몸이 지휘하는 고르디우스 봉인전대의 일원으로서 활동하게 될 것이다.","JPN":"わしが仕切るゴルディウス封印戦隊の一員として活動することになる。","ENG":"You will all become members of Gordias Seal Division under my command.","TWN":"成為我指揮的戈爾迪亞封印戰隊的一員。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>본체의 바이탈사인 정지를 확인…… 예비체 활성화.</color>","JPN":"<color=#ffd34c>本体のバイタルサイン停止を確認……予備体活性化。</color>","ENG":"<color=#ffd34c>Entity vital sign arrest confirmed... Activating backup shell.</color>","TWN":"<color=#ffd34c>確認主體的生命徵象停止……啟動預備體。</color>"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_12"},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>프로젝트 오라클…… 최종 시퀀스 돌입.</color>","JPN":"<color=#ffd34c>プロジェクトオラクル……最終シーケンスに突入。</color>","ENG":"<color=#ffd34c>Project Oracle... Entering final sequence.</color>","TWN":"<color=#ffd34c>甲骨文計畫……進入最終序列。</color>"},"stage":{"bg":"LABORATORY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_12"}]`);export{e as default};